import axios from "axios";
import { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import { useProgress } from "../context/ProgressContext";

const LEVELS = [
  {
    id: 0,
    name: "Beginner",
    emoji: "🌱",
    bar: "bg-green-500",
    iconBg: "bg-green-500/10",
    iconBorder: "border-green-500/30",
    badge: "bg-green-500/10 text-green-400 border-green-500/20",
    card: "border-green-500/20",
  },
  {
    id: 1,
    name: "Elementary",
    emoji: "📖",
    bar: "bg-blue-500",
    iconBg: "bg-blue-500/10",
    iconBorder: "border-blue-500/30",
    badge: "bg-blue-500/10 text-blue-400 border-blue-500/20",
    card: "border-blue-500/20",
  },
  {
    id: 2,
    name: "Intermediate",
    emoji: "🗣️",
    bar: "bg-violet-500",
    iconBg: "bg-violet-500/10",
    iconBorder: "border-violet-500/30",
    badge: "bg-violet-500/10 text-violet-400 border-violet-500/20",
    card: "border-violet-500/20",
  },
  {
    id: 3,
    name: "Upper-Inter.",
    emoji: "📡",
    bar: "bg-amber-500",
    iconBg: "bg-amber-500/10",
    iconBorder: "border-amber-500/30",
    badge: "bg-amber-500/10 text-amber-400 border-amber-500/20",
    card: "border-amber-500/20",
  },
  {
    id: 4,
    name: "Advanced",
    emoji: "🏆",
    bar: "bg-pink-500",
    iconBg: "bg-pink-500/10",
    iconBorder: "border-pink-500/30",
    badge: "bg-pink-500/10 text-pink-400 border-pink-500/20",
    card: "border-pink-500/20",
  },
];

const ROADMAP = [
  { id: 0, name: "Beginner", emoji: "🌱" },
  { id: 1, name: "Elementary", emoji: "📖" },
  { id: 2, name: "Pre-Inter.", emoji: "💬" },
  { id: 3, name: "Intermediate", emoji: "🗣️" },
  { id: 4, name: "Upper-Int.", emoji: "📡" },
  { id: 5, name: "Advanced", emoji: "🏆" },
];

const DAYS_PER_LEVEL = 2;
const TOTAL_SECTIONS = 8;

export default function HomePage() {
  const { user } = useAuth();
  const { allProgress, fetchAllProgress } = useProgress();
  const navigate = useNavigate();

  useEffect(() => {
    fetchAllProgress();
    axios.get("/api/lessons").catch(() => {});
  }, []);

  function getProgress(levelId, day) {
    return (
      allProgress.find((p) => p.level === levelId && p.day === day) || null
    );
  }

  function isUnlocked(levelId) {
    if (levelId === 0) return true;
    return Array.from({ length: DAYS_PER_LEVEL }, (_, i) => i + 1).every(
      (d) => getProgress(levelId - 1, d)?.isCompleted,
    );
  }

  function levelPct(levelId) {
    const done = Array.from({ length: DAYS_PER_LEVEL }, (_, i) =>
      getProgress(levelId, i + 1)?.isCompleted ? 1 : 0,
    ).reduce((a, b) => a + b, 0);
    return Math.round((done / DAYS_PER_LEVEL) * 100);
  }

  const totalCompleted = allProgress.filter((p) => p.isCompleted).length;
  const totalLessons = LEVELS.length * DAYS_PER_LEVEL;
  const overallPct = Math.round((totalCompleted / totalLessons) * 100);
  const currentLevel = user?.currentLevel || 0;

  return (
    <div className="min-h-screen bg-[#0f1117]">
      <div className="max-w-3xl mx-auto px-4 py-6 space-y-4">
        {/* ── HERO CARD ── */}
        <div className="relative overflow-hidden rounded-2xl border border-indigo-500/20 bg-gradient-to-br from-[#1a1f35] via-[#0f172a] to-[#1e1040] p-6">
          <div className="pointer-events-none absolute -right-10 -top-10 h-44 w-44 rounded-full bg-violet-500/10 blur-3xl" />
          <div className="pointer-events-none absolute -bottom-8 -left-5 h-36 w-36 rounded-full bg-blue-500/10 blur-3xl" />

          <div className="relative">
            <div className="flex items-start justify-between mb-5">
              <div>
                <p className="text-xs font-bold text-slate-400 mb-1">
                  Good day 👋
                </p>
                <h1 className="font-playfair text-2xl font-bold text-slate-100 leading-tight">
                  {user?.name?.split(" ")[0]}
                </h1>
                <p className="text-xs text-slate-500 mt-1">
                  Fluency is closer than you think.
                </p>
              </div>
              <div className="rounded-xl border border-orange-500/30 bg-orange-500/10 px-4 py-2 text-center">
                <p className="text-xl font-black text-orange-400">
                  🔥 {user?.streak || 0}
                </p>
                <p className="text-[10px] font-bold text-orange-500/70 mt-0.5">
                  day streak
                </p>
              </div>
            </div>

            <div className="grid grid-cols-3 gap-3 mb-5">
              {[
                {
                  label: "Total XP",
                  value: user?.totalXP || 0,
                  color: "text-yellow-400",
                },
                {
                  label: "Completed",
                  value: totalCompleted,
                  color: "text-green-400",
                },
                {
                  label: "Remaining",
                  value: totalLessons - totalCompleted,
                  color: "text-blue-400",
                },
              ].map((s) => (
                <div
                  key={s.label}
                  className="rounded-xl border border-white/5 bg-white/[0.03] p-2.5 text-center"
                >
                  <p className={`text-xl font-black ${s.color}`}>{s.value}</p>
                  <p className="text-[10px] font-bold text-slate-500">
                    {s.label}
                  </p>
                </div>
              ))}
            </div>

            <div>
              <div className="flex justify-between text-[11px] font-bold mb-1.5">
                <span className="text-slate-500">Overall Progress</span>
                <span className="text-slate-400">
                  {overallPct}% · {totalCompleted}/{totalLessons}
                </span>
              </div>
              <div className="h-2 w-full overflow-hidden rounded-full bg-white/5">
                <div
                  className="h-full rounded-full bg-gradient-to-r from-indigo-500 to-pink-500 transition-all duration-700"
                  style={{ width: `${overallPct}%` }}
                />
              </div>
            </div>
          </div>
        </div>

        {/* ── ROADMAP ── */}
        <div className="rounded-2xl border border-white/[0.07] bg-[#161b27] p-5">
          <p className="mb-4 text-[11px] font-extrabold uppercase tracking-widest text-slate-500">
            🗺️ Learning Roadmap
          </p>
          <div className="flex overflow-x-auto pb-1 scrollbar-hide">
            {ROADMAP.map((step, i) => {
              const isDone = i < currentLevel;
              const isActive = i === currentLevel;
              const isLocked = i > currentLevel;
              return (
                <div
                  key={step.id}
                  className="relative flex min-w-[88px] flex-col items-center"
                >
                  {i < ROADMAP.length - 1 && (
                    <div
                      className={`absolute left-[58%] top-[18px] z-0 h-0.5 w-[calc(100%-12px)] transition-colors duration-500 ${isDone ? "bg-indigo-500" : "bg-white/[0.07]"}`}
                    />
                  )}
                  <div
                    className={`relative z-10 flex h-9 w-9 items-center justify-center rounded-full border-2 text-base transition-all duration-300
                    ${isDone ? "border-indigo-500 bg-indigo-500 text-white text-sm font-bold" : ""}
                    ${isActive ? "border-pink-500 bg-pink-500/10 shadow-[0_0_0_4px_rgba(236,72,153,0.15)]" : ""}
                    ${isLocked ? "border-white/10 bg-white/[0.03] opacity-40" : ""}
                  `}
                  >
                    {isDone ? "✓" : step.emoji}
                  </div>
                  <p
                    className={`mt-1.5 max-w-[80px] text-center text-[10px] font-bold leading-tight
                    ${isDone ? "text-indigo-400" : isActive ? "text-pink-400" : "text-slate-600"}
                  `}
                  >
                    {step.name}
                  </p>
                </div>
              );
            })}
          </div>
        </div>

        {/* ── ALL LESSONS ── */}
        <div>
          <p className="mb-3 text-[11px] font-extrabold uppercase tracking-widest text-slate-500">
            📚 All Lessons
          </p>
          <div className="space-y-3">
            {LEVELS.map((lvl) => {
              const unlocked = isUnlocked(lvl.id);
              const pct = levelPct(lvl.id);
              return (
                <div
                  key={lvl.id}
                  className={`rounded-2xl border bg-[#161b27] p-5 transition-all duration-300 ${unlocked ? lvl.card : "border-white/[0.06] opacity-50"}`}
                >
                  <div className="flex items-center justify-between mb-3">
                    <div className="flex items-center gap-3">
                      <div
                        className={`flex h-10 w-10 items-center justify-center rounded-xl border text-lg ${lvl.iconBg} ${lvl.iconBorder}`}
                      >
                        {lvl.emoji}
                      </div>
                      <div>
                        <p className="text-sm font-extrabold text-slate-100">
                          {lvl.name}
                        </p>
                        <p className="text-[11px] font-semibold text-slate-500">
                          {unlocked
                            ? `${pct}% complete`
                            : "🔒 Finish previous level"}
                        </p>
                      </div>
                    </div>
                    <span
                      className={`rounded-full border px-3 py-1 text-xs font-extrabold ${lvl.badge}`}
                    >
                      {pct}%
                    </span>
                  </div>

                  <div className="mb-4 h-1 w-full overflow-hidden rounded-full bg-white/[0.06]">
                    <div
                      className={`h-full rounded-full transition-all duration-700 ${lvl.bar}`}
                      style={{ width: `${pct}%` }}
                    />
                  </div>

                  <div className="grid grid-cols-2 gap-3">
                    {Array.from({ length: DAYS_PER_LEVEL }, (_, i) => {
                      const dayNum = i + 1;
                      const prog = getProgress(lvl.id, dayNum);
                      const isCompleted = prog?.isCompleted;
                      const inProgress = prog && !isCompleted;
                      const doneSections = Object.values(
                        prog?.completedSections || {},
                      ).filter(Boolean).length;
                      const dayLocked =
                        !unlocked ||
                        (dayNum === 2 && !getProgress(lvl.id, 1)?.isCompleted);

                      return (
                        <button
                          key={dayNum}
                          disabled={dayLocked}
                          onClick={() =>
                            !dayLocked &&
                            navigate(`/lesson/${lvl.id}/${dayNum}`)
                          }
                          className={`group w-full rounded-xl border p-3.5 text-left transition-all duration-200
                            ${isCompleted ? "border-green-500/25 bg-green-500/[0.07] hover:-translate-y-0.5 hover:shadow-lg" : ""}
                            ${inProgress ? `${lvl.card} ${lvl.iconBg} hover:-translate-y-0.5 hover:shadow-lg` : ""}
                            ${!prog && !dayLocked ? "border-white/[0.07] bg-white/[0.02] hover:-translate-y-0.5 hover:border-white/20 hover:shadow-lg" : ""}
                            ${dayLocked ? "cursor-not-allowed border-white/[0.05] bg-white/[0.01] opacity-50" : "cursor-pointer"}
                          `}
                        >
                          <div className="flex items-center justify-between mb-2.5">
                            <div className="flex items-center gap-2">
                              <span className="text-base">
                                {isCompleted
                                  ? "✅"
                                  : inProgress
                                    ? "▶️"
                                    : dayLocked
                                      ? "🔒"
                                      : "📅"}
                              </span>
                              <span className="text-sm font-extrabold text-slate-100">
                                Day {dayNum}
                              </span>
                            </div>
                            <span
                              className={`rounded-full px-2 py-0.5 text-[10px] font-extrabold
                              ${isCompleted ? "bg-green-500/15 text-green-400" : ""}
                              ${inProgress ? lvl.badge : ""}
                              ${!prog && !dayLocked ? "bg-white/[0.06] text-slate-500" : ""}
                              ${dayLocked ? "bg-white/[0.04] text-slate-600" : ""}
                            `}
                            >
                              {isCompleted
                                ? "Done"
                                : inProgress
                                  ? "In Progress"
                                  : dayLocked
                                    ? "Locked"
                                    : "Start"}
                            </span>
                          </div>

                          <div className="flex items-center gap-2">
                            <div className="h-1 flex-1 overflow-hidden rounded-full bg-white/[0.06]">
                              <div
                                className={`h-full rounded-full transition-all duration-500 ${isCompleted ? "bg-green-500" : lvl.bar}`}
                                style={{
                                  width: `${(doneSections / TOTAL_SECTIONS) * 100}%`,
                                }}
                              />
                            </div>
                            <span className="whitespace-nowrap text-[10px] font-extrabold text-slate-600">
                              {doneSections}/{TOTAL_SECTIONS}
                            </span>
                          </div>

                          {!dayLocked && (
                            <p className="mt-2 text-[10px] font-bold text-slate-600 opacity-0 transition-opacity group-hover:opacity-100">
                              {isCompleted
                                ? "Review →"
                                : inProgress
                                  ? "Continue →"
                                  : "Start →"}
                            </p>
                          )}
                        </button>
                      );
                    })}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}
